ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/education#>
PREFIX p: <http://ambrosia.example.org/education/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT ?description WHERE {
  ?learningactivity a :LearningActivities .
  ?purpose a :Purpose .
  ?learningactivity p:hasPurpose ?purpose .
  ?learningactivity p:Description ?description .
  ?learningactivity p:ActivityType ?activitytype_w .
  ?learningactivity p:ActivityType ?activitytype_w2 .
  ?purpose p:name ?name_w .
  FILTER((((STR(?activitytype_w) = "Field Trip" || STR(?activitytype_w2) = "Study Group")) && STR(?name_w) = "Problem Solving Skills Development"))
} }
  low: { SELECT ?description WHERE {
  ?learningactivity a :LearningActivities .
  ?purpose a :Purpose .
  ?learningactivity p:hasPurpose ?purpose .
  ?learningactivity p:Description ?description .
  ?learningactivity p:ActivityType ?activitytype_w .
  ?learningactivity p:ActivityType ?activitytype_w2 .
  ?purpose p:name ?name_w .
  FILTER((STR(?activitytype_w) = "Field Trip" || (STR(?activitytype_w2) = "Study Group" && STR(?name_w) = "Problem Solving Skills Development")))
} }
}
